def build_tree(node, char):
    if node is None:
        return {'val': char, 'left': None, 'right': None}
    if char < node['val']:
        node['left'] = build_tree(node['left'], char)
    elif char > node['val']:
        node['right'] = build_tree(node['right'], char)
    return node

